//refAssemblies: TCAdmin.Web.Shared.dll
using System;
using System.IO;
using System.IO.Compression;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY

// Bedrock dedicated server provisioning (Windows). See the Linux sibling for rationale.
// Mojang's CDN needs a browser User-Agent; resolve the latest URL from the official links API.
const string Ua = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0 Safari/537.36";
const string BaseFolderName = "minecraft-bedrock";
bool isWin = ThisGame.OperatingSystem == EOperatingSystem.Windows;

// 1) Ensure the auto-setup base folder exists before the create "copy game files" step.
string rdNorm = ThisService.RootDirectory;
rdNorm = rdNorm.Replace("\\", "/");
int iu = rdNorm.IndexOf("/users/", StringComparison.OrdinalIgnoreCase);
if (iu > 0)
{
    string baseFolder = Path.Combine(rdNorm.Substring(0, iu), "games", BaseFolderName);
    try
    {
        if (!Directory.Exists(baseFolder))
        {
            Directory.CreateDirectory(baseFolder);
            ScriptConsole.WriteLine($"Created base folder {baseFolder}");
        }
    }
    catch (Exception ex) { ScriptConsole.WriteLine($"Base folder note: {ex.Message}"); }
}

// 2) Download + extract the Bedrock server if not already installed.
string root = ThisService.RootDirectory;
string exeName = isWin ? "bedrock_server.exe" : "bedrock_server";
string exePath = Path.Combine(root, exeName);
if (Directory.Exists(root) && !File.Exists(exePath))
{
    using (var http = new HttpClient { Timeout = TimeSpan.FromMinutes(10) })
    {
        http.DefaultRequestHeaders.Add("User-Agent", Ua);
        string url = null;
        string linksJson = await http.GetStringAsync("https://net-secondary.web.minecraft-services.net/api/v1.0/download/links", ThisCancellationToken);
        using (JsonDocument doc = JsonDocument.Parse(linksJson))
        {
            string want = isWin ? "serverBedrockWindows" : "serverBedrockLinux";
            foreach (JsonElement l in doc.RootElement.GetProperty("result").GetProperty("links").EnumerateArray())
            {
                if (l.TryGetProperty("downloadType", out JsonElement dt) && dt.GetString() == want)
                {
                    url = l.GetProperty("downloadUrl").GetString();
                    break;
                }
            }
        }
        if (string.IsNullOrEmpty(url))
            throw new Exception("Could not resolve Bedrock download URL from Mojang links API.");

        ScriptConsole.WriteLine($"Downloading Bedrock server: {url}");
        string zipPath = Path.Combine(root, "bedrock-server.zip");
        byte[] data = await http.GetByteArrayAsync(url, ThisCancellationToken);
        await File.WriteAllBytesAsync(zipPath, data, ThisCancellationToken);
        ScriptConsole.WriteLine($"Downloaded {data.Length} bytes; extracting...");

        using (ZipArchive zip = ZipFile.OpenRead(zipPath))
        {
            foreach (ZipArchiveEntry e in zip.Entries)
            {
                string rel = e.FullName.Replace('\\', '/');
                string dest = Path.Combine(root, rel);
                if (rel.EndsWith("/")) { Directory.CreateDirectory(dest); continue; }
                string destDir = Path.GetDirectoryName(dest);
                if (!string.IsNullOrEmpty(destDir)) Directory.CreateDirectory(destDir);
                if (!File.Exists(dest)) e.ExtractToFile(dest, false);
            }
        }
        try { File.Delete(zipPath); } catch { }

        if (!isWin && File.Exists(exePath))
        {
            try
            {
                File.SetUnixFileMode(exePath,
                    UnixFileMode.UserRead | UnixFileMode.UserWrite | UnixFileMode.UserExecute |
                    UnixFileMode.GroupRead | UnixFileMode.GroupExecute |
                    UnixFileMode.OtherRead | UnixFileMode.OtherExecute);
            }
            catch (Exception ex) { ScriptConsole.WriteLine($"chmod note: {ex.Message}"); }
        }
        ScriptConsole.WriteLine(File.Exists(exePath) ? "Bedrock server installed." : "WARNING: bedrock_server not found after extract.");
    }
}

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, TCAdmin.Web.Shared.dll
using System;
using System.Net.Http;
using System.Text.Json;
using System.Threading.Tasks;
using TCAdmin.SDK.Hubs.Models.GameQuery;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

string address = Variables.Parse<string>("Address", ThisService.IPAddress);
int port = Variables.Parse<int>("Port", ThisService.QueryPort);

string data;
using (var http = new HttpClient { Timeout = TimeSpan.FromSeconds(8) })
{
    data = await http.GetStringAsync($"https://api.mcstatus.io/v2/status/bedrock/{address}:{port}", ThisCancellationToken);
}

int numPlayers = 0;
int maxPlayers = ThisService.Slots;
string name = "Minecraft Bedrock";
bool online = false;
using (var doc = JsonDocument.Parse(data))
{
    var root = doc.RootElement;
    online = root.TryGetProperty("online", out JsonElement onl) && onl.ValueKind == JsonValueKind.True;
    if (root.TryGetProperty("players", out JsonElement players) && players.ValueKind == JsonValueKind.Object)
    {
        if (players.TryGetProperty("online", out JsonElement on) && on.ValueKind == JsonValueKind.Number) numPlayers = on.GetInt32();
        if (players.TryGetProperty("max", out JsonElement mx) && mx.ValueKind == JsonValueKind.Number) maxPlayers = mx.GetInt32();
    }
    if (root.TryGetProperty("motd", out JsonElement motd) && motd.ValueKind == JsonValueKind.Object
        && motd.TryGetProperty("clean", out JsonElement clean) && clean.ValueKind == JsonValueKind.String)
        name = clean.GetString();
}

Globals.ReturnValue = new GameQueryResponse
{
    Status = online ? "online" : "offline",
    Hostname = $"{address}:{port}",
    Name = name,
    GameType = "Minecraft Bedrock",
    Map = "Unknown",
    NumPlayers = numPlayers,
    MaxPlayers = maxPlayers,
};

